var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"03:40 PM 관리국 재건도시        \\nARC-KS1: 구 서울        \\n침식재난 대피소        \\n<color=#ffd34c>유미나, 김소빈, 프리덤 라이더즈</color>        ","JPN":"03:40 PM 管理局再建都市\\nARC-KS1: \\n侵食災害避難所\\n<color=#ffd34c>ヤナギ・ミナ、アマナ・コハル、フリーダム・ライダーズ</color>        ","ENG":"[[","TWN":"晚上22:40 管理局重建城市 \\nARC-KS1:舊首爾 \\n侵蝕災難避難所 \\n<color=#ffd34c>劉米娜、金素蘋、自由騎士</color>","THA":"15.40 น. เมืองบูรณะใหม่โดยองค์การบริหารโลก        \\nARC-KS1: กรุงโซลเก่า        \\nที่หลบภัยคอร์รัปชั่น        \\n<color=#ffd34c>ยู มีนา, คิม โซบิน, ฟรีดอมไรเดอร์ส</color>        ","VTN":"3:40 CHIỀU Thành Phố Tái Thiết Quản Trị        \\nARC-KS1: Seoul Cũ       \\nNhà Trú Ẩn Tai Họa Ăn Mòn        \\n<color=#ffd34c>Yoo Mina, Kim Sobin, Freedom Riders</color>        ","SCN":"3:40PM   管理局重建城市        \\nARC-KS1: 旧首尔         \\n侵蚀灾难避难所        \\n<color=#ffd34c>刘米娜，静香，自由乘风者</color>","DEU":"[[","FRA":"15\xA0h\xA040 Cité Reconstruite par l'Administration        \\nCRA-KS1\xA0: Ancienne Séoul        \\nAbri anti sinistres de corruption        \\n<color=#ffd34c>Yoo Mina, Kim Sobin, les Freedom Riders</color>        "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>CSE</color> Lv. <b>1</b>   ","JPN":"<color=#ffd34c>CSE</color> Lv. <b>1</b>","ENG":"<color=#ffd34c>CSE</color> Lv. <b>1</b>   ","TWN":"<color=#ffd34c>CSE</color> Lv. <b>1</b>","THA":"<color=#ffd34c>CSE</color> ระดับ <b>1</b>   ","VTN":"<color=#ffd34c>CSE</color> Cấp <b>1</b>   ","SCN":"<color=#ffd34c>CSE</color> Lv. <b>1</b>","DEU":"<color=#ffd34c>CSE</color>-St.\xA0<b>1</b>   ","FRA":"<color=#ffd34c>ECM</color> niv.\xA0<b>1</b>   "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국 재건도시 KS1 도시관리국에서 안내 말씀 드립니다.</color>","JPN":"<color=#ffd34c>管理局再建都市KS1都市管理局からご案内申し上げます。</color>","ENG":"<color=#ffd34c>This is an announcement from the Administration Rebuilt City KS1 City Managements.</color>","TWN":"<color=#ffd34c>管理局重建城市KS1城市管理局為您導覽。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>금일 오후 3시경, 도시 전역에 침식 재난이 발생한 상태입니다.</color>","JPN":"<color=#ffd34c>本日の午後3時頃、都市全域に侵食災害が発生しました。</color>","ENG":"<color=#ffd34c>A corruption disaster occurred throughout the city around 15:00 today.</color>","TWN":"<color=#ffd34c>今日下午3點左右，市內全域發生了侵蝕災難。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>특별 재난 대책 조약에 의거, 도시 방어 및 치안 유지는 본 도시관리국에서 총괄하고 있습니다.</color>","JPN":"<color=#ffd34c>特別災害対策条約に基づき、都市防御および治安の維持は、\\nこちら都市管理局で一括管理しています。</color>","ENG":"<color=#ffd34c>In accordance with the special disaster plan, the City Managements are in charge of defending the city and maintaining public order.</color>","TWN":"<color=#ffd34c>根據特殊災難條約，城市防禦及治安由本城市管理局總管。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>또한 현재, 본 국의 요청으로 출격한 핀리 하이어드 소속의 용병 부대가 침식체를 빠르게 격퇴 중입니다.</color>","JPN":"<color=#ffd34c>現在、本局からの要請により出撃しているフィンリー・ハイアード所属の傭兵部隊が\\n速やかに侵食体を撃退しています。</color>","ENG":"<color=#ffd34c>Further, mercenaries from Finley Hired are currently destroying the Corrupted Objects at the request of this administration.</color>","TWN":"<color=#ffd34c>另外，芬利傭兵團的部隊目前已經應本局要求出動，正迅速地擊退侵蝕體。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시민 여러분께서는 동요하지 마시고 용병 부대의 인도에 따라 즉시 가까운 대피소로 이동하여 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>市民の皆様は動揺せず、傭兵部隊の案内にそって直ちに\\n近くの避難所に移動してください。</color>","ENG":"<color=#ffd34c>We urge everyone to stay calm and immediately go to the nearest shelter at the guidance of these mercenaries.</color>","TWN":"<color=#ffd34c>請各位市民不要慌張，遵從傭兵部隊的指示，即刻前往附近的避難所避難。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"통신은 여전히 안 돼?","JPN":"連絡はまだつかない？","ENG":"You still can't get in touch with anyone?","TWN":"還是無法通信嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"계, 계속 먹통이에요.","JPN":"い、依然として通じません。","ENG":"I-it's still silent.","TWN":"一、一直都沒辦法。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"위, 위상 장벽은 전파도 차단한다고 들었어요. 아마 그것 때문인 거 같아요.","JPN":"位相防壁は電波をも遮断すると聞きました。たぶんそのせいかと……","ENG":"I-I heard that the phase barrier jams radio signals. That must be why.","TWN":"我、我聽說相位屏障也能阻斷電波，大概是因為這個原因吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"애초에 그 방벽이란 걸 쳐둔 이유가 뭐지?","JPN":"そもそも、その防壁とやらを設置した理由はなんだろう？","ENG":"What's that barrier for in the first place?","TWN":"話說回來，他們為什麼要在這裡設置這個屏障？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"침식체들이 방벽 밖에서 쳐들어오는 것도 아닐 텐데.......","JPN":"侵食体が防壁の外側から攻めてくるわけでもないだろうに……","ENG":"It's not like the Corrupted Objects are coming from outside the barrier...","TWN":"侵蝕體又不會從屏障外面打進來。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이래서야 독 안에 갇힌 생쥐 신세잖아?","JPN":"これじゃ、まるで袋のネズミじゃない。","ENG":"We're pretty much fish in a barrel like this!","TWN":"我們這樣不就變成了籠子裡的老鼠嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"도시관리국도 수상하긴 마찬가지야.","JPN":"怪しいのは都市管理局も一緒だよ。","ENG":"There's something suspicious about the City Managements, too.","TWN":"城市管理局也很反常啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"이런 일이 있으면 관리국 조례에 따라 도시 내의 카운터를 모두 소집하는 게 정상이라고.","JPN":"こういう時は管理局の条例に基づいて、市内のカウンター全員を招集するのが普通なのに。","ENG":"Normally in a crisis like this, they would have mobilized all the Counters in the city according to the Administration's regulations.","TWN":"要是出現這種事情，按照管理局的條例，應該會把城市內的所有制裁者都召集起來才對。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"하지만 아무 연락도 없잖아?","JPN":"何の連絡もなかったよね？","ENG":"But we haven't heard anything from the city, right?","TWN":"但我們完全沒有接到聯絡耶？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......저 녀석들만 빼고 말이지.","JPN":"……あいつらを除いてだけど。","ENG":"But they sure did...","TWN":"……除了那些傢伙。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};